// Script Continued Below
function onLoad() {

	if(!g_user.hasRole('x_153465_discovert.tasker_process_template_global') ){
		if(g_form.getValue('template_name') == "") g_form.removeOption('process_level','global_process');
		//if(g_form.getValue('template_name') != "") g_form.removeOption('process_level','global_process');
	}

	// STRY0079396 
	if(!g_scratchpad.isOuTemplateDesigner){
		//  STRY0143870
		// this did not work for the run template
		// had to adjust to NOT remove if the original value 
		if(g_form.getValue('template_name') == "" && g_form.getValue("process_level") != "ou_process") 
			g_form.removeOption('process_level','ou_process');
		//if(g_form.getValue('template_name') != "") g_form.removeOption('process_level','ou_process');
	}

	if(!g_user.hasRole('x_153465_discovert.tasker_process_template_user') ){
		if(g_form.getValue('template_name') == "") g_form.removeOption('process_level','my_process');
		//if(g_form.getValue('template_name') != "") g_form.removeOption('process_level','ou_process');
	}

}
